#include <imgui.h>
#include <cmath>

void DrawAnimationExample() {
    static bool panel_open = true;
    static float alpha = 0.18f;
    static float scale = 0.92f;
    static float progress = 0.0f;
    static float hover_mix = 0.0f;
    static float press_flash = 0.0f;

    ImGuiIO& io = ImGui::GetIO();
    const float target_alpha = panel_open ? 0.96f : 0.10f;
    const float target_scale = panel_open ? 1.0f : 0.94f;
    alpha += (target_alpha - alpha) * io.DeltaTime * 8.0f;
    scale += (target_scale - scale) * io.DeltaTime * 8.0f;
    progress = fmodf(progress + io.DeltaTime * 0.25f, 1.0f);
    press_flash = ImMax(0.0f, press_flash - io.DeltaTime * 2.5f);

    ImGui::SetNextWindowBgAlpha(alpha);
    ImGui::SetNextWindowSize(ImVec2(320.0f * scale, 220.0f * scale));
    ImGui::Begin("Animated Tools");
    if (ImGui::Button(panel_open ? "Fade Out" : "Fade In")) {
        panel_open = !panel_open;
        press_flash = 1.0f;
    }

    const bool hovered = ImGui::IsItemHovered();
    hover_mix += ((hovered ? 1.0f : 0.0f) - hover_mix) * io.DeltaTime * 12.0f;

    ImVec4 base_color(0.20f, 0.36f, 0.58f, 1.0f);
    ImVec4 hover_color(0.32f, 0.52f, 0.82f, 1.0f);
    ImVec4 animated_color(
        base_color.x + (hover_color.x - base_color.x) * hover_mix,
        base_color.y + (hover_color.y - base_color.y) * hover_mix,
        base_color.z + (hover_color.z - base_color.z) * hover_mix,
        1.0f
    );

    ImGui::PushStyleColor(ImGuiCol_PlotHistogram, animated_color);
    ImGui::ProgressBar(progress, ImVec2(260.0f, 0.0f), "Loading");
    ImGui::PopStyleColor();

    ImGui::Text("alpha: %.2f", alpha);
    ImGui::Text("scale: %.2f", scale);
    ImGui::Text("hover_mix: %.2f", hover_mix);
    ImGui::Text("press_flash: %.2f", press_flash);
    ImGui::End();
}

