#include <imgui.h>

void DrawAnimatedSidebarExample() {
    static bool sidebar_open = true;
    static float sidebar_width = 120.0f;
    static float toast_alpha = 0.0f;
    static float toast_lifetime = 0.0f;

    ImGuiIO& io = ImGui::GetIO();
    const float target_width = sidebar_open ? 280.0f : 94.0f;
    sidebar_width += (target_width - sidebar_width) * io.DeltaTime * 10.0f;

    if (toast_lifetime > 0.0f) {
        toast_lifetime -= io.DeltaTime;
    }
    const float target_alpha = toast_lifetime > 0.0f ? 0.96f : 0.0f;
    toast_alpha += (target_alpha - toast_alpha) * io.DeltaTime * 9.0f;

    ImGui::SetNextWindowPos(ImVec2(24.0f, 82.0f));
    ImGui::SetNextWindowSize(ImVec2(sidebar_width, 340.0f));
    ImGui::Begin("Sidebar", nullptr, ImGuiWindowFlags_NoResize | ImGuiWindowFlags_NoCollapse);
    if (ImGui::Button(sidebar_open ? "Collapse" : "Expand")) {
        sidebar_open = !sidebar_open;
    }
    if (ImGui::Button("Show Toast")) {
        toast_lifetime = 2.4f;
    }
    ImGui::Separator();
    ImGui::Text("width: %.1f", sidebar_width);
    ImGui::Text("toast_alpha: %.2f", toast_alpha);
    ImGui::Text("toast_lifetime: %.2f", toast_lifetime);
    ImGui::End();

    if (toast_alpha > 0.02f) {
        ImGui::SetNextWindowPos(ImVec2(860.0f, 42.0f));
        ImGui::SetNextWindowBgAlpha(toast_alpha);
        ImGui::Begin("Toast", nullptr, ImGuiWindowFlags_NoDecoration | ImGuiWindowFlags_AlwaysAutoResize);
        ImGui::Text("Save completed");
        ImGui::Text("The notification fades out automatically.");
        ImGui::End();
    }
}

