#include <imgui.h>

void DrawExplosionEditorExample() {
    static float blast_time = 1.0f;
    static float blast_speed = 96.0f;
    static float shard_spread = 78.0f;

    ImGuiIO& io = ImGui::GetIO();
    blast_time += io.DeltaTime;

    ImGui::Begin("Explosion Editor");
    if (ImGui::Button("Trigger Explosion")) {
        blast_time = 0.0f;
    }
    ImGui::SliderFloat("Blast Speed", &blast_speed, 40.0f, 180.0f);
    ImGui::SliderFloat("Shard Spread", &shard_spread, 24.0f, 160.0f);

    ImVec2 canvas_min = ImGui::GetCursorScreenPos();
    ImVec2 canvas_size(340.0f, 220.0f);
    ImGui::InvisibleButton("explosion_canvas", canvas_size);
    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    ImVec2 center(canvas_min.x + 170.0f, canvas_min.y + 110.0f);
    float radius = blast_time * blast_speed;
    float alpha = ImClamp(1.0f - blast_time * 0.55f, 0.0f, 1.0f);

    draw_list->AddRectFilled(canvas_min, ImVec2(canvas_min.x + canvas_size.x, canvas_min.y + canvas_size.y), IM_COL32(18, 24, 34, 255), 14.0f);
    draw_list->AddCircleFilled(center, 18.0f + blast_time * 18.0f, IM_COL32(255, 183, 78, (int)(alpha * 120.0f)));
    draw_list->AddCircle(center, radius, IM_COL32(255, 208, 116, (int)(alpha * 255.0f)), 0, 3.0f);
    draw_list->AddCircle(center, radius * 0.72f, IM_COL32(255, 120, 84, (int)(alpha * 180.0f)), 0, 2.0f);

    for (int i = 0; i < 8; ++i) {
        float x = center.x + ((i - 3.5f) * 12.0f) * blast_time;
        float y = center.y + ((i % 3) - 1.0f) * shard_spread * 0.12f * blast_time;
        draw_list->AddRectFilled(ImVec2(x - 4.0f, y - 4.0f), ImVec2(x + 4.0f, y + 4.0f), IM_COL32(255, 206, 128, (int)(alpha * 255.0f)), 2.0f);
    }

    ImGui::Text("Blast time: %.2f", blast_time);
    ImGui::End();
}

