#include <imgui.h>

void DrawGlowEditorExample() {
    static float glow_radius = 28.0f;
    static float glow_intensity = 0.86f;
    static float glow_color[4] = {0.35f, 0.74f, 1.0f, 1.0f};

    ImGui::Begin("Glow Editor");
    ImGui::SliderFloat("Glow Radius", &glow_radius, 12.0f, 72.0f);
    ImGui::SliderFloat("Glow Intensity", &glow_intensity, 0.10f, 1.0f);
    ImGui::ColorEdit4("Glow Color", glow_color);

    ImVec2 canvas_min = ImGui::GetCursorScreenPos();
    ImVec2 canvas_size(320.0f, 200.0f);
    ImGui::InvisibleButton("glow_canvas", canvas_size);
    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    ImVec2 center(canvas_min.x + 160.0f, canvas_min.y + 96.0f);

    draw_list->AddRectFilled(canvas_min, ImVec2(canvas_min.x + canvas_size.x, canvas_min.y + canvas_size.y), IM_COL32(15, 20, 30, 255), 14.0f);
    for (int layer = 4; layer >= 1; --layer) {
        float layer_radius = glow_radius + layer * 18.0f;
        int alpha = (int)(glow_intensity * 34.0f * layer);
        draw_list->AddCircleFilled(center, layer_radius, IM_COL32((int)(glow_color[0] * 255.0f), (int)(glow_color[1] * 255.0f), (int)(glow_color[2] * 255.0f), alpha));
    }
    draw_list->AddCircleFilled(center, glow_radius, IM_COL32(255, 244, 220, 255));
    draw_list->AddCircle(center, glow_radius + 8.0f, IM_COL32(255, 255, 255, 120), 0, 2.0f);
    ImGui::Text("Glow intensity: %.2f", glow_intensity);
    ImGui::End();
}

