#include <imgui.h>

void DrawScatterEditorExample() {
    static float particle_time = 0.0f;
    static float scatter_speed = 1.2f;
    static float scatter_spread = 72.0f;
    static int particle_count = 14;

    particle_time += ImGui::GetIO().DeltaTime;
    if (particle_time > 1.6f) {
        particle_time = 0.0f;
    }

    ImGui::Begin("Scatter Editor");
    ImGui::SliderFloat("Speed", &scatter_speed, 0.2f, 3.0f);
    ImGui::SliderFloat("Spread", &scatter_spread, 20.0f, 140.0f);
    ImGui::SliderInt("Count", &particle_count, 6, 24);

    ImVec2 canvas_min = ImGui::GetCursorScreenPos();
    ImVec2 canvas_size(340.0f, 210.0f);
    ImGui::InvisibleButton("scatter_canvas", canvas_size);
    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    ImVec2 center(canvas_min.x + 170.0f, canvas_min.y + 104.0f);

    draw_list->AddRectFilled(canvas_min, ImVec2(canvas_min.x + canvas_size.x, canvas_min.y + canvas_size.y), IM_COL32(17, 24, 35, 255), 14.0f);
    draw_list->AddCircleFilled(center, 8.0f, IM_COL32(255, 202, 114, 255));

    for (int i = 0; i < particle_count; ++i) {
        float n = (float)i / (float)particle_count;
        float dx = cosf(n * IM_PI * 2.0f);
        float dy = sinf(n * IM_PI * 2.0f);
        float dist = scatter_spread * particle_time * scatter_speed;
        ImVec2 pos(center.x + dx * dist, center.y + dy * dist * 0.72f);
        draw_list->AddCircleFilled(pos, 3.0f + n * 2.0f, IM_COL32(111, 192, 255, 220));
    }

    ImGui::Text("Scatter time: %.2f", particle_time);
    ImGui::End();
}
